import java.io.*;
import java.util.*;

public class Main {
    static final long INF = Long.MAX_VALUE / 4;
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append('\n');
        }
        // Replace escaped "\n" sequences (if any) with spaces to handle inputs that use literal backslash-n
        String all = raw.toString().replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(all);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int n = Integer.parseInt(st.nextToken());
            int m = Integer.parseInt(st.nextToken());
            long[][] dist = new long[n][n];
            for (int i = 0; i < n; i++) {
                Arrays.fill(dist[i], INF);
                dist[i][i] = 0;
            }
            for (int i = 0; i < m; i++) {
                int u = Integer.parseInt(st.nextToken()) - 1;
                int v = Integer.parseInt(st.nextToken()) - 1;
                long w = Long.parseLong(st.nextToken());
                if (w < dist[u][v]) {
                    dist[u][v] = w;
                    dist[v][u] = w;
                }
            }
            for (int k = 0; k < n; k++) {
                for (int i = 0; i < n; i++) {
                    if (dist[i][k] == INF) continue;
                    for (int j = 0; j < n; j++) {
                        if (dist[k][j] == INF) continue;
                        long nd = dist[i][k] + dist[k][j];
                        if (nd < dist[i][j]) dist[i][j] = nd;
                    }
                }
            }
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    if (dist[i][j] == INF) out.append("-1");
                    else out.append(dist[i][j]);
                    if (j + 1 < n) out.append(' ');
                }
                out.append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

